    "ax.plot(forecast['date'], forecast['forecast_revenue'], color='#E8A33D', linestyle='--', label='Forecast')\n",
    "ax.fill_between(forecast['date'], forecast['lower_80'], forecast['upper_80'], color='#E8A33D', alpha=0.15, label='80% CI')\n",
    "ax.set_title('Revenue: Last 150 Days Actual + 90-Day Forecast')\n",
    "ax.legend()\n",
    "plt.xticks(rotation=45)\n",
    "plt.tight_layout()\n",
    "plt.savefig('../docs/img/forecast.png', dpi=110, bbox_inches='tight')\n",
    "plt.show()\n",
    "\n",
